const express = require('express');
const session = require('express-session');
const axios = require('axios');
const { Issuer, generators } = require('openid-client');
const crypto = require('crypto');

const app = express();

const OIDC_ISSUER = process.env.OIDC_ISSUER || 'https://accounts.google.com';
const CLIENT_ID = process.env.CLIENT_ID;
const CLIENT_SECRET = process.env.CLIENT_SECRET;
const REDIRECT_URI = process.env.REDIRECT_URI || 'http://localhost:3000/callback';
const SESSION_SECRET = process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex');

app.use(session({
  secret: SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 24 * 60 * 60 * 1000
  }
}));

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

let oidcClient;

async function initializeOIDC() {
  const issuer = await Issuer.discover(OIDC_ISSUER);
  
  oidcClient = new issuer.Client({
    client_id: CLIENT_ID,
    client_secret: CLIENT_SECRET,
    redirect_uris: [REDIRECT_URI],
    response_types: ['code'],
  });
}

app.get('/login', (req, res) => {
  const code_verifier = generators.codeVerifier();
  const code_challenge = generators.codeChallenge(code_verifier);
  const state = generators.state();
  const nonce = generators.nonce();

  req.session.code_verifier = code_verifier;
  req.session.state = state;
  req.session.nonce = nonce;

  const authorizationUrl = oidcClient.authorizationUrl({
    scope: 'openid email profile',
    code_challenge,
    code_challenge_method: 'S256',
    state,
    nonce
  });

  res.redirect(authorizationUrl);
});

app.get('/callback', async (req, res) => {
  try {
    const params = oidcClient.callbackParams(req);
    
    if (!req.session.state || params.state !== req.session.state) {
      return res.status(400).send('Invalid state parameter');
    }

    const code_verifier = req.session.code_verifier;
    const nonce = req.session.nonce;

    const tokenSet = await oidcClient.callback(REDIRECT_URI, params, {
      code_verifier,
      state: req.session.state,
      nonce
    });

    const claims = tokenSet.claims();

    if (claims.nonce !== nonce) {
      return res.status(400).send('Invalid nonce in ID token');
    }

    if (claims.aud !== CLIENT_ID) {
      return res.status(400).send('Invalid audience in ID token');
    }

    const currentTime = Math.floor(Date.now() / 1000);
    if (claims.exp && claims.exp < currentTime) {
      return res.status(400).send('ID token has expired');
    }

    if (claims.iat && claims.iat > currentTime + 60) {
      return res.status(400).send('ID token issued in the future');
    }

    req.session.user = {
      sub: claims.sub,
      email: claims.email,
      name: claims.name,
      email_verified: claims.email_verified
    };

    req.session.access_token = tokenSet.access_token;
    req.session.id_token = tokenSet.id_token;

    delete req.session.code_verifier;
    delete req.session.state;
    delete req.session.nonce;

    res.redirect('/profile');
  } catch (error) {
    console.error('Authentication error:', error);
    res.status(500).send('Authentication failed');
  }
});

app.get('/profile', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }

  res.json({
    message: 'User profile',
    user: req.session.user
  });
});

app.get('/logout', (req, res) => {
  const id_token_hint = req.session.id_token;
  
  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
    }
    
    if (oidcClient.issuer.metadata.end_session_endpoint) {
      const logoutUrl = oidcClient.endSessionUrl({
        id_token_hint,
        post_logout_redirect_uri: process.env.POST_LOGOUT_REDIRECT_URI || 'http://localhost:3000'
      });
      res.redirect(logoutUrl);
    } else {
      res.redirect('/');
    }
  });
});

app.get('/', (req, res) => {
  res.send(`
    <h1>OIDC Authentication Demo</h1>
    ${req.session.user ? 
      `<p>Welcome, ${req.session.user.name || req.session.user.email}!</p>
       <a href="/profile">View Profile</a> | <a href="/logout">Logout</a>` :
      `<a href="/login">Login with OIDC</a>`
    }
  `);
});

initializeOIDC().then(() => {
  const PORT = process.env.PORT || 3000;
  app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}).catch(error => {
  console.error('Failed to initialize OIDC:', error);
  process.exit(1);
});